// Phase 5.4: TypeChecker 주입 - 타입 검증 후 컴파일
const checker = new TypeChecker();
const typeResult = checker.check(ast);
if (!typeResult.success) {
  return typeResult.errors.map(e => `[TypeError] ${e.message}`);
}

// Fast path: no imports → compile directly (zero overhead)
const hasImports = ast.stmts.some(s => s.kind === "import");
if (!hasImports && !ast.stmts.some(s => s.kind === "export")) {
  // Phase 5.5: typeEnv 전달 (Typed Op 생성용)
  const chunk = compile(ast, typeResult.success ? typeResult.types : undefined);
  const vm = new VM(chunk);
  return vm.run().output;
}

// Merge module stmts into a single AST
const allStmts: Stmt[] = [];
const base = basePath ?? process.cwd();
